class SecureApiClient {
  static _baseUrl = '';
  static _authToken = null;
  static _certificatePins = new Map();

  static configure({ baseUrl, authToken, certificatePins }) {
    this._baseUrl = baseUrl;
    this._authToken = authToken;
    if (certificatePins) {
      this._certificatePins = new Map(Object.entries(certificatePins));
    }
  }

  static setAuthToken(token) {
    this._authToken = token;
  }

  static async request(endpoint, options = {}) {
    const url = `${this._baseUrl}${endpoint}`;

    const headers = {
      'Content-Type': 'application/json',
      'X-Platform': Platform.OS,
      'X-App-Version': getAppVersion(),
      'X-Request-ID': generateRequestId(),
      ...options.headers,
    };

    if (this._authToken) {
      headers['Authorization'] = `Bearer ${this._authToken}`;
    }

    // Use native module for certificate pinning
    const { NetworkSecurityModule } = NativeModules;
    if (NetworkSecurityModule?.pinnedFetch) {
      const response = await NetworkSecurityModule.pinnedFetch(url, {
        ...options,
        headers,
        pins: this._certificatePins.get(new URL(url).hostname) || [],
      });
      if (!response.ok) {
        throw new PaymentError(
          `API request failed: ${response.status}`,
          PaymentErrorCode.NETWORK_ERROR
        );
      }
      return JSON.parse(response.body);
    }

    // Fallback to standard fetch (less secure, log warning)
    console.warn('Certificate pinning unavailable - using standard fetch');
    const response = await fetch(url, { ...options, headers });
    if (!response.ok) {
      const errorBody = await response.text().catch(() => '');
      throw new PaymentError(
        `API request failed: ${response.status} ${errorBody}`,
        PaymentErrorCode.NETWORK_ERROR
      );
    }
    return response.json();
  }
}

