class SecureStorage {
  static async store(key, value) {
    const { KeychainModule } = NativeModules;
    if (Platform.OS === 'ios' && KeychainModule?.setItem) {
      return KeychainModule.setItem(key, JSON.stringify(value), {
        accessible: 'whenUnlockedThisDeviceOnly',
        accessGroup: getKeychainAccessGroup(),
      });
    } else if (Platform.OS === 'android' && KeychainModule?.setItem) {
      return KeychainModule.setItem(key, JSON.stringify(value), {
        securityLevel: 'SECURE_HARDWARE',
      });
    }
    throw new PaymentError(
      'Secure storage unavailable',
      PaymentErrorCode.SECURITY_ERROR
    );
  }

  static async retrieve(key) {
    const { KeychainModule } = NativeModules;
    if (KeychainModule?.getItem) {
      const value = await KeychainModule.getItem(key);
      return value ? JSON.parse(value) : null;
    }
    throw new PaymentError(
      'Secure storage unavailable',
      PaymentErrorCode.SECURITY_ERROR
    );
  }

  static async remove(key) {
    const { KeychainModule } = NativeModules;
    if (KeychainModule?.removeItem) {
      return KeychainModule.removeItem(key);
    }
  }

  static async clearAll() {
    const { KeychainModule } = NativeModules;
    if (KeychainModule?.clearAll) {
      return KeychainModule.clearAll();
    }
  }
}

