class SensitiveDataHandler {
  static maskCardNumber(cardNumber) {
    if (!cardNumber || cardNumber.length < 8) return '****';
    const cleaned = cardNumber.replace(/\s/g, '');
    return `****${cleaned.slice(-4)}`;
  }

  static maskEmail(email) {
    if (!email) return '***';
    const [local, domain] = email.split('@');
    if (!domain) return '***';
    const maskedLocal = local.length > 2
      ? `${local[0]}${'*'.repeat(local.length - 2)}${local[local.length - 1]}`
      : '**';
    return `${maskedLocal}@${domain}`;
  }

  static sanitizeForLogging(data) {
    if (!data || typeof data !== 'object') return data;

    const sensitiveKeys = new Set([
      'cardNumber', 'cvv', 'cvc', 'securityCode', 'pin',
      'password', 'token', 'accessToken', 'refreshToken',
      'accountNumber', 'routingNumber', 'ssn', 'taxId',
      'privateKey', 'secret', 'apiKey',
    ]);

    const sanitized = {};
    for (const [key, value] of Object.entries(data)) {
      if (sensitiveKeys.has(key)) {
        sanitized[key] = '[REDACTED]';
      } else if (typeof value === 'object' && value !== null) {
        sanitized[key] = this.sanitizeForLogging(value);
      } else {
        sanitized[key] = value;
      }
    }
    return sanitized;
  }

  // Securely clear sensitive data from memory
  static secureClear(obj) {
    if (!obj || typeof obj !== 'object') return;
    for (const key of Object.keys(obj)) {
      if (typeof obj[key] === 'string') {
        obj[key] = '\0'.repeat(obj[key].length);
        obj[key] = '';
      } else if (typeof obj[key] === 'object') {
        this.secureClear(obj[key]);
      }
      delete obj[key];
    }
  }
}

