  IAP_PURCHASE_FAILED: 'IAP_PURCHASE_FAILED',
  IAP_RECEIPT_VALIDATION_FAILED: 'IAP_RECEIPT_VALIDATION_FAILED',
  WALLET_NOT_AVAILABLE: 'WALLET_NOT_AVAILABLE',
